export declare const styles = "\n\n*{\nmargin:0;\npadding:0;\nbox-sizing:border-box;\n}\n\n:root{\n\n--bg:#0f172a;\n--surface:#1e293b;\n--surface-2:#111827;\n\n--border:#334155;\n\n--text:#ffffff;\n--muted:#94a3b8;\n\n--primary:#2563eb;\n\n--success:#22c55e;\n--warning:#f59e0b;\n--danger:#ef4444;\n--info:#3b82f6;\n\n}\n\nbody{\n\nbackground:var(--bg);\n\ncolor:var(--text);\n\nbackground:var(--bg);\n\ncolor:var(--text);\n\nfont-family:\"Roboto Condensed\",sans-serif;\n\n-webkit-font-smoothing:antialiased;\n\n-moz-osx-font-smoothing:grayscale;\n\ntext-rendering:optimizeLegibility;\n\npadding:40px;\n\nline-height:1.5;\n\n}\n\n.container{\n\nmax-width:1150px;\n\nmargin:auto;\n\n}\n\nh2{\n\nmargin:42px 0 20px;\n\nfont-size:26px;\n\n}\n\ntable{\n\nwidth:100%;\n\nborder-collapse:collapse;\n\n}\n\nth{\n\nbackground:#273449;\n\npadding:16px;\n\ntext-align:left;\n\nfont-size:13px;\n\ntext-transform:uppercase;\n\nletter-spacing:.5px;\n\n}\n\ntd{\n\npadding:16px;\n\nborder-top:1px solid var(--border);\n\nvertical-align:top;\n\n}\n\n.hero{\n\ntext-align:center;\n\nmargin-bottom:50px;\n\n}\n\n.hero h1{\n\nfont-size:52px;\n\nmargin-bottom:12px;\n\n}\n\n.hero p{\n\ncolor:var(--muted);\n\nfont-size:18px;\n\nmargin-bottom:24px;\n\n}\n\n.score-wrapper{\n\ndisplay:flex;\n\nflex-direction:column;\n\nalign-items:center;\n\nmargin:40px 0 50px;\n\n}\n\n.score-ring{\n\nwidth:220px;\n\nheight:220px;\n\nborder-radius:50%;\n\ndisplay:flex;\n\njustify-content:center;\n\nalign-items:center;\n\nposition:relative;\n\nflex-shrink:0;\n\n}\n\n.score-ring::before{\n\ncontent:\"\";\n\nposition:absolute;\n\nwidth:180px;\n\nheight:180px;\n\nbackground:var(--bg);\n\nborder-radius:50%;\n\n}\n\n.score-value{\n\nposition:relative;\n\nz-index:2;\n\ndisplay:flex;\n\nflex-direction:column;\n\nalign-items:center;\n\njustify-content:center;\n\nfont-size:64px;\n\nfont-weight:700;\n\nline-height:1;\n\n}\n\n.score-value span{\n\nmargin-top:8px;\n\nfont-size:22px;\n\nfont-weight:500;\n\ncolor:var(--muted);\n\n}\n\n.score-wrapper h2{\n\nmargin-top:24px;\n\nfont-size:22px;\n\nfont-weight:500;\n\ncolor:var(--muted);\n\n}\n\n.stats{\n\ndisplay:grid;\n\ngrid-template-columns:repeat(3,1fr);\n\ngap:20px;\n\nmargin-bottom:50px;\n\n}\n\n.card{\n\nbackground:linear-gradient(\n180deg,\nvar(--surface),\n#172033\n);\n\nborder:1px solid var(--border);\n\nborder-radius:16px;\n\npadding:28px;\n\nposition:relative;\n\noverflow:hidden;\n\ntransition:.25s;\n\n}\n\n.card::before{\n\ncontent:\"\";\n\nposition:absolute;\n\nleft:0;\n\ntop:0;\n\nwidth:100%;\n\nheight:4px;\n\nbackground:var(--accent);\n\n}\n\n.card:hover{\n\ntransform:translateY(-4px);\n\nborder-color:#4f46e5;\n\nbox-shadow:0 12px 30px rgba(0,0,0,.30);\n\n}\n\n.card h3{\n\nfont-size:14px;\n\ncolor:var(--muted);\n\nmargin-bottom:14px;\n\n}\n\n.card p{\n\nfont-size:34px;\n\nfont-weight:700;\n\n}\n\n.icon{\n\nfont-size:36px;\n\nmargin-bottom:18px;\n\nfilter:drop-shadow(\n0 0 8px rgba(255,255,255,.15)\n);\n\n}\n\n.dashboard-grid{\n\ndisplay:grid;\n\ngrid-template-columns:1fr 1fr;\n\ngap:24px;\n\nmargin:40px 0 50px;\n\n}\n\n.dashboard-card{\n\nbackground:var(--surface);\n\nborder:1px solid var(--border);\n\nborder-radius:18px;\n\npadding:24px;\n\nbox-shadow:0 4px 20px rgba(0,0,0,.18);\n\n}\n\n.dashboard-card h2{\n\nmargin-top:0;\n\n}\n\n.issues-table{\n\nwidth:100%;\n\nborder-collapse:collapse;\n\nmargin-top:24px;\n\nbackground:var(--surface);\n\nborder-radius:14px;\n\noverflow:hidden;\n\n}\n\n.issues-table tr:hover{\n\nbackground:#263548;\n\n}\n\n.severity{\n\ndisplay:inline-block;\n\npadding:6px 12px;\n\nborder-radius:999px;\n\nfont-size:12px;\n\nfont-weight:700;\n\n}\n\n.error{\n\nbackground:#7f1d1d;\n\ncolor:#fecaca;\n\n}\n\n.warning{\n\nbackground:#78350f;\n\ncolor:#fde68a;\n\n}\n\n.info{\n\nbackground:#1e3a8a;\n\ncolor:#bfdbfe;\n\n}\n\n.rule-bars{\n\ndisplay:flex;\n\nflex-direction:column;\n\ngap:18px;\n\nmargin-top:24px;\n\n}\n\n.rule-row{\n\ndisplay:flex;\n\nflex-direction:column;\n\ngap:8px;\n\n}\n\n.rule-header{\n\ndisplay:flex;\n\njustify-content:space-between;\n\nalign-items:center;\n\nfont-weight:600;\n\n}\n\n.bar{\n\nheight:10px;\n\nbackground:var(--border);\n\nborder-radius:999px;\n\noverflow:hidden;\n\n}\n\n.fill{\n\nheight:100%;\n\nborder-radius:999px;\n\nbackground:linear-gradient(\n90deg,\n#3b82f6,\n#8b5cf6\n);\n\n}\n\n.worst-files{\n\ndisplay:flex;\n\nflex-direction:column;\n\ngap:20px;\n\nmargin-top:20px;\n\n}\n\n.worst-file{\n\nbackground:var(--surface-2);\n\nborder:1px solid var(--border);\n\nborder-radius:14px;\n\npadding:20px;\n\n}\n\n.wf-header{\n\ndisplay:flex;\n\njustify-content:space-between;\n\nalign-items:center;\n\nmargin-bottom:12px;\n\n}\n\n.wf-name{\n\nfont-weight:600;\n\nfont-size:15px;\n\n}\n\n.wf-score{\n\nfont-weight:700;\n\nfont-size:15px;\n\n}\n\n.wf-bar{\n\nheight:12px;\n\nbackground:var(--border);\n\nborder-radius:999px;\n\noverflow:hidden;\n\nmargin-bottom:10px;\n\n}\n\n.wf-fill{\n\nheight:100%;\n\nborder-radius:999px;\n\ntransition:width .35s ease;\n\n}\n\n.wf-footer{\n\nfont-size:13px;\n\ncolor:var(--muted);\n\n}\n\n/* ===========================\n   DataGrid\n=========================== */\n\n.table-toolbar{\n\ndisplay:flex;\n\njustify-content:space-between;\n\nalign-items:center;\n\ngap:20px;\n\nmargin-bottom:20px;\n\n}\n\n.table-search{\n\nflex:1;\n\nbackground:var(--surface-2);\n\nborder:1px solid var(--border);\n\nborder-radius:10px;\n\npadding:12px 16px;\n\ncolor:white;\n\nfont-size:14px;\n\noutline:none;\n\n}\n\n.table-search:focus{\n\nborder-color:var(--primary);\n\n}\n\n.rows-select{\n\nbackground:var(--surface-2);\n\nborder:1px solid var(--border);\n\nborder-radius:10px;\n\npadding:12px 16px;\n\ncolor:white;\n\ncursor:pointer;\n\n}\n\n.table-footer{\n\ndisplay:flex;\n\njustify-content:space-between;\n\nalign-items:center;\n\nmargin-top:20px;\n\n}\n\n.page-info{\n\nfont-size:14px;\n\ncolor:var(--muted);\n\n}\n\n.pagination{\n\ndisplay:flex;\n\ngap:8px;\n\nflex-wrap:wrap;\n\n}\n\n.pagination button{\n\nbackground:#1f2937;\n\nborder:1px solid var(--border);\n\ncolor:white;\n\npadding:8px 14px;\n\nborder-radius:8px;\n\ncursor:pointer;\n\ntransition:.2s;\n\n}\n\n.pagination button:hover{\n\nbackground:#374151;\n\n}\n\n.pagination button.active{\n\nbackground:var(--primary);\n\n}\n\n.pagination button:disabled{\n\nopacity:.35;\n\ncursor:not-allowed;\n\n}\n\n/* ===========================\n   Recommendations\n=========================== */\n\n.recommendation-grid{\n\ndisplay:grid;\n\ngrid-template-columns:repeat(auto-fit,minmax(320px,1fr));\n\ngap:20px;\n\nmargin-top:20px;\n\n}\n\n.recommendation-card{\n\nbackground:var(--surface);\n\nborder-left:4px solid var(--primary);\n\nborder-radius:14px;\n\npadding:24px;\n\ntransition:.25s;\n\n}\n\n.recommendation-card:hover{\n\ntransform:translateY(-3px);\n\nbackground:#263548;\n\n}\n\n.recommendation-card h3{\n\nfont-size:14px;\n\nmargin-bottom:12px;\n\n}\n\n.recommendation-card h4{\n\nfont-size:20px;\n\nmargin-bottom:12px;\n\n}\n\n.recommendation-card p{\n\ncolor:var(--muted);\n\nline-height:1.7;\n\n}\n\n/* ===========================\n   Accordion\n=========================== */\n\n.accordion{\n\nmargin:36px 0;\n\nbackground:var(--surface);\n\nborder:1px solid var(--border);\n\nborder-radius:18px;\n\noverflow:hidden;\n\n}\n\n.accordion summary{\n\ndisplay:flex;\n\nalign-items:center;\n\npadding:22px 28px;\n\ncursor:pointer;\n\nfont-size:22px;\n\nfont-weight:700;\n\nlist-style:none;\n\nuser-select:none;\n\n}\n\n.accordion summary::-webkit-details-marker{\n\ndisplay:none;\n\n}\n\n.accordion-badge{\n\nmargin-left:auto;\n\nbackground:var(--primary);\n\ncolor:white;\n\npadding:5px 12px;\n\nborder-radius:999px;\n\nfont-size:12px;\n\nfont-weight:700;\n\n}\n\n.accordion summary::after{\n\ncontent:\"\u25BC\";\n\nmargin-left:16px;\n\nfont-size:13px;\n\ntransition:.25s;\n\n}\n\n.accordion:not([open]) summary::after{\n\ntransform:rotate(-90deg);\n\n}\n\n.accordion-content{\n\npadding:28px;\n\nborder-top:1px solid var(--border);\n\n}\n\n/* ===========================\n   Footer\n=========================== */\n\n.footer{\n\nmargin-top:80px;\n\npadding:40px 0;\n\ncolor:var(--muted);\n\n}\n\n.footer hr{\n\nborder:none;\n\nborder-top:1px solid var(--border);\n\nmargin-bottom:28px;\n\n}\n\n.footer-content{\n\ndisplay:flex;\n\njustify-content:space-between;\n\nalign-items:center;\n\nflex-wrap:wrap;\n\ngap:20px;\n\nfont-size:14px;\n\n}\n\n.footer-content strong{\n\ncolor:white;\n\n}\n\n.footer a{\n\ncolor:#60a5fa;\n\ntext-decoration:none;\n\n}\n\n.footer a:hover{\n\ntext-decoration:underline;\n\n}\n\n/* ===========================\n   Responsive\n=========================== */\n\n@media (max-width:1000px){\n\n.stats{\n\ngrid-template-columns:repeat(2,1fr);\n\n}\n\n.dashboard-grid{\n\ngrid-template-columns:1fr;\n\n}\n\n}\n\n\n.score-meta{\n\nmargin-top:18px;\n\ncolor:var(--muted);\n\nfont-size:14px;\n\nfont-weight:500;\n\n}\n\n@media (max-width:700px){\n\nbody{\n\npadding:20px;\n\n}\n\n.stats{\n\ngrid-template-columns:1fr;\n\n}\n\n.table-toolbar{\n\nflex-direction:column;\n\nalign-items:stretch;\n\n}\n\n.table-footer{\n\nflex-direction:column;\n\ngap:16px;\n\nalign-items:flex-start;\n\n}\n\n.issues-table{\n\ndisplay:block;\n\noverflow-x:auto;\n\nwhite-space:nowrap;\n\n}\n\n.score-ring{\n\nwidth:180px;\n\nheight:180px;\n\n}\n\n.score-ring::before{\n\nwidth:145px;\n\nheight:145px;\n\n}\n\n.score-value{\n\nfont-size:48px;\n\n}\n\n.hero h1{\n\nfont-size:38px;\n\n}\n\nh2{\n\nfont-size:22px;\n\n}\n\n}\n\n";
